Building an AI chatbot is one of the best ways to learn the OpenAI API. In this tutorial, we'll build a full-stack chatbot with streaming responses, conversation history, and a clean React frontend — in about 30 minutes.

## What We're Building

- Node.js/Express backend that calls the OpenAI API
- Streaming responses (text appears as it generates)
- Conversation history (the bot remembers context)
- React frontend with a chat UI

## Backend Setup

```bash
mkdir ai-chatbot && cd ai-chatbot
npm init -y
npm install express openai cors dotenv
```

Create `server.js`:

```javascript
import express from 'express'
import OpenAI from 'openai'
import cors from 'cors'
import 'dotenv/config'

const app = express()
app.use(cors())
app.use(express.json())

const client = new OpenAI()

const SYSTEM_PROMPT = `You are a helpful AI assistant. You are concise, friendly, and accurate.
If you don't know something, say so. Never make up information.`

app.post('/api/chat', async (req, res) => {
  const { messages } = req.body

  // Set headers for streaming
  res.setHeader('Content-Type', 'text/event-stream')
  res.setHeader('Cache-Control', 'no-cache')
  res.setHeader('Connection', 'keep-alive')

  try {
    const stream = await client.chat.completions.create({
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: SYSTEM_PROMPT },
        ...messages
      ],
      stream: true,
      max_tokens: 1000
    })

    for await (const chunk of stream) {
      const content = chunk.choices[0]?.delta?.content || ''
      if (content) {
        res.write(`data: ${JSON.stringify({ content })}

`)
      }
    }

    res.write('data: [DONE]

')
    res.end()
  } catch (err) {
    res.write(`data: ${JSON.stringify({ error: err.message })}

`)
    res.end()
  }
})

app.listen(3001, () => console.log('Server running on port 3001'))
```

## React Frontend

```jsx
import { useState, useRef, useEffect } from 'react'

export default function ChatBot() {
  const [messages, setMessages] = useState([])
  const [input, setInput] = useState('')
  const [streaming, setStreaming] = useState(false)
  const bottomRef = useRef(null)

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  async function sendMessage(e) {
    e.preventDefault()
    if (!input.trim() || streaming) return

    const userMessage = { role: 'user', content: input }
    const newMessages = [...messages, userMessage]
    setMessages(newMessages)
    setInput('')
    setStreaming(true)

    // Add empty assistant message to stream into
    setMessages(prev => [...prev, { role: 'assistant', content: '' }])

    const res = await fetch('http://localhost:3001/api/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ messages: newMessages })
    })

    const reader = res.body.getReader()
    const decoder = new TextDecoder()

    while (true) {
      const { done, value } = await reader.read()
      if (done) break

      const lines = decoder.decode(value).split('\n')
      for (const line of lines) {
        if (!line.startsWith('data: ')) continue
        const data = line.slice(6)
        if (data === '[DONE]') break

        try {
          const { content } = JSON.parse(data)
          setMessages(prev => {
            const updated = [...prev]
            updated[updated.length - 1] = {
              ...updated[updated.length - 1],
              content: updated[updated.length - 1].content + content
            }
            return updated
          })
        } catch {}
      }
    }

    setStreaming(false)
  }

  return (
    <div className="chatbot">
      <div className="chatbot__messages">
        {messages.map((msg, i) => (
          <div key={i} className={`message message--${msg.role}`}>
            <span className="message__role">{msg.role === 'user' ? 'You' : 'AI'}</span>
            <p>{msg.content}</p>
          </div>
        ))}
        <div ref={bottomRef} />
      </div>
      <form className="chatbot__input" onSubmit={sendMessage}>
        <input
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="Ask anything..."
          disabled={streaming}
        />
        <button type="submit" disabled={streaming || !input.trim()}>
          {streaming ? 'Thinking...' : 'Send'}
        </button>
      </form>
    </div>
  )
}
```

## Running It

```bash
# Terminal 1 — backend
node server.js

# Terminal 2 — frontend
npm run dev
```

## What to Add Next

- **Persistent history:** Save conversations to localStorage or a database
- **Multiple personas:** Let users switch between different system prompts
- **File uploads:** Use the vision API to analyze images
- **Voice input:** Use the Web Speech API for voice-to-text
- **Rate limiting:** Add express-rate-limit to prevent abuse

This is the foundation of most AI products. Once you have streaming chat working, you can build almost anything on top of it.
